/**
 * @summary Send a message and get AI response
 */
export const getSendMessageUrl = (sessionId: number) => {
  return `/api/chat/sessions/${sessionId}/messages`;
};

export const sendMessage = async (
  sessionId: number,
  sendMessageRequest: SendMessageRequest,
  options?: RequestInit,
): Promise<SendMessageResponse> => {
  return customFetch<SendMessageResponse>(getSendMessageUrl(sessionId), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(sendMessageRequest),
  });
};

export const getSendMessageMutationOptions = <
  TError = ErrorType<ErrorResponse>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof sendMessage>>,
    TError,
    { sessionId: number; data: BodyType<SendMessageRequest> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof sendMessage>>,
  TError,
  { sessionId: number; data: BodyType<SendMessageRequest> },
  TContext
> => {
  const mutationKey = ["sendMessage"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof sendMessage>>,
    { sessionId: number; data: BodyType<SendMessageRequest> }
  > = (props) => {
    const { sessionId, data } = props ?? {};

    return sendMessage(sessionId, data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type SendMessageMutationResult = NonNullable<
  Awaited<ReturnType<typeof sendMessage>>
>;
export type SendMessageMutationBody = BodyType<SendMessageRequest>;
export type SendMessageMutationError = ErrorType<ErrorResponse>;

